export interface LessonQuizQuestion {
  question: string;
  options: string[];
  correctAnswer: number;
  explanation: string;
}

export interface Lesson {
  title: string;
  explanation: string;
  keyPoints: string[];
  workedExamples: { problem: string; steps: string[]; answer: string }[];
  tips: string[];
  quiz: LessonQuizQuestion[];
  // Optional VCE-style extended sections
  definitions?: { term: string; meaning: string }[];
  formulas?: { name: string; formula: string; note?: string }[];
  examQuestion?: { problem: string; solution: string[]; answer: string; marks?: number };
  commonErrors?: string[];
  summary?: string[];
  practice?: { question: string; answer: string }[];
}

export type TopicLessonsMap = Record<string, Lesson[]>;

// ─── PROGRESS HELPERS ───────────────────────────────────────────────
const STORAGE_KEY = "lesson_progress";
const TOPIC_QUIZ_KEY = "topic_quiz_progress";
const CATEGORY_QUIZ_KEY = "category_quiz_progress";

export function getLessonProgress(): Record<string, Record<number, boolean>> {
  try {
    return JSON.parse(localStorage.getItem(STORAGE_KEY) || "{}");
  } catch {
    return {};
  }
}

export function markLessonComplete(topicId: string, lessonIndex: number) {
  const progress = getLessonProgress();
  if (!progress[topicId]) progress[topicId] = {};
  progress[topicId][lessonIndex] = true;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(progress));
}

export function isLessonComplete(topicId: string, lessonIndex: number): boolean {
  return getLessonProgress()[topicId]?.[lessonIndex] === true;
}

export function areAllLessonsComplete(topicId: string, totalLessons: number): boolean {
  const progress = getLessonProgress()[topicId];
  if (!progress) return false;
  for (let i = 0; i < totalLessons; i++) {
    if (!progress[i]) return false;
  }
  return true;
}

// ─── TOPIC QUIZ PROGRESS ────────────────────────────────────────────
function getTopicQuizProgress(): Record<string, boolean> {
  try {
    return JSON.parse(localStorage.getItem(TOPIC_QUIZ_KEY) || "{}");
  } catch {
    return {};
  }
}

export function markTopicQuizComplete(topicId: string) {
  const progress = getTopicQuizProgress();
  progress[topicId] = true;
  localStorage.setItem(TOPIC_QUIZ_KEY, JSON.stringify(progress));
}

export function isTopicQuizComplete(topicId: string): boolean {
  return getTopicQuizProgress()[topicId] === true;
}

// ─── CATEGORY QUIZ PROGRESS ────────────────────────────────────────
interface CategoryQuizResult {
  complete: boolean;
  bestPercentage: number;
}

function getCategoryQuizProgress(): Record<string, CategoryQuizResult> {
  try {
    const raw = localStorage.getItem(CATEGORY_QUIZ_KEY);
    if (!raw) return {};
    const parsed = JSON.parse(raw);
    // Migrate old boolean format
    const result: Record<string, CategoryQuizResult> = {};
    for (const [key, val] of Object.entries(parsed)) {
      if (typeof val === "boolean") {
        result[key] = { complete: val, bestPercentage: val ? 100 : 0 };
      } else {
        result[key] = val as CategoryQuizResult;
      }
    }
    return result;
  } catch {
    return {};
  }
}

export function markCategoryQuizComplete(categoryId: string, percentage: number = 100) {
  const progress = getCategoryQuizProgress();
  const existing = progress[categoryId];
  progress[categoryId] = {
    complete: true,
    bestPercentage: Math.max(percentage, existing?.bestPercentage ?? 0),
  };
  localStorage.setItem(CATEGORY_QUIZ_KEY, JSON.stringify(progress));
}

export function isCategoryQuizComplete(categoryId: string): boolean {
  return getCategoryQuizProgress()[categoryId]?.complete === true;
}

export function getCategoryQuizBestScore(categoryId: string): number {
  return getCategoryQuizProgress()[categoryId]?.bestPercentage ?? 0;
}

/** Chapter mastered = Category Review ≥ 85% AND all lesson quizzes attempted */
export function isChapterMastered(categoryId: string, topics: { id: string; lessons: number }[]): boolean {
  const bestScore = getCategoryQuizBestScore(categoryId);
  if (bestScore < 85) return false;
  // All topics must have all lessons completed (at least attempted)
  return topics.every(t => areAllLessonsComplete(t.id, t.lessons));
}

// ─── AGGREGATED PROGRESS ────────────────────────────────────────────
/** Topic progress: lessons = 80%, topic quiz = 20% */
export function getTopicCompletionPercent(topicId: string, totalLessons: number): number {
  const progress = getLessonProgress()[topicId];
  if (!progress) return 0;
  const done = Object.values(progress).filter(Boolean).length;
  const lessonPercent = Math.round((done / totalLessons) * 80);
  const quizPercent = isTopicQuizComplete(topicId) ? 20 : 0;
  return Math.min(100, lessonPercent + quizPercent);
}

/** Category progress: average of topic progresses */
export function getCategoryCompletionPercent(
  topics: { id: string; lessons: number }[]
): number {
  if (topics.length === 0) return 0;
  const total = topics.reduce((sum, t) => sum + getTopicCompletionPercent(t.id, t.lessons), 0);
  return Math.round(total / topics.length);
}

/** Whether all topics in a category are 100% complete */
export function areAllTopicsComplete(topics: { id: string; lessons: number }[]): boolean {
  return topics.every(t => getTopicCompletionPercent(t.id, t.lessons) === 100);
}

/** Year progress: average of category progresses */
export function getYearCompletionPercent(
  categories: { topics: { id: string; lessons: number }[] }[]
): number {
  if (categories.length === 0) return 0;
  const total = categories.reduce((sum, cat) => sum + getCategoryCompletionPercent(cat.topics), 0);
  return Math.round(total / categories.length);
}

